prettier:
/**
 * formats a user label
 * @param {string} [value='guest'] user label text
 * @returns {string} normalized label text
 */
export function formatLabel(value: string = 'guest') {
  return value.trim().toUpperCase();
}

oxfmt:
/**
 * Formats a user label.
 *
 * @param {string} [value='guest'] User label text. Default is `'guest'`
 *
 * @returns {string} Normalized label text
 */
export function formatLabel(value: string = 'guest') {
  return value.trim().toUpperCase();
}
